#include <bits/stdc++.h>
using namespace std;

const int N=110,M=2010,mod=998244353;

int n,m,a[N][M],s[N],f[2][N<<1];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            scanf("%d",&a[i][j]);
            s[i]=(s[i]+a[i][j])%mod;
        }
    int ans=1;
    for(int i=1;i<=n;i++)
        ans=1LL*ans*(s[i]+1)%mod;
    ans--;
    //printf("%d\n",ans);
    for(int i=1;i<=m;i++){
        memset(f[0],0,sizeof(f[0]));
        f[0][n]=1;
        for(int j=1;j<=n;j++){
            memset(f[j&1],0,sizeof(f[j&1]));
            for(int k=0;k<=2*n;k++){
                f[j&1][k]=(f[j&1][k]+1LL*f[(j&1)^1][k+1]*a[j][i])%mod;
                if(k)
                    f[j&1][k]=(f[j&1][k]+1LL*f[(j&1)^1][k-1]*(s[j]-a[j][i]))%mod;
                f[j&1][k]=(f[j&1][k]+f[(j&1)^1][k])%mod;
            }
        }
        int sum=0;
        for(int j=0;j<n;j++)
            sum=(sum+f[n&1][j])%mod;
        //printf("%d\n",sum);
        ans=(ans-sum)%mod;
    }
    printf("%d",(ans+mod)%mod);
    return 0;
}
